&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot; data-ccp-parastyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;679f3b2c-153b-5071-bf1d-4b0991a9f682|1&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[201342446,&amp;quot;1&amp;quot;,201342447,&amp;quot;5&amp;quot;,201342448,&amp;quot;1&amp;quot;,201342449,&amp;quot;1&amp;quot;,469777841,&amp;quot;Times New Roman&amp;quot;,469777842,&amp;quot;Times New Roman&amp;quot;,469777843,&amp;quot;Times New Roman&amp;quot;,469777844,&amp;quot;Times New Roman&amp;quot;,201341986,&amp;quot;1&amp;quot;,469769226,&amp;quot;Times New Roman&amp;quot;,268442635,&amp;quot;24&amp;quot;,469775450,&amp;quot;font-claude-response-body&amp;quot;,201340122,&amp;quot;2&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;font-claude-response-body&amp;quot;,335572020,&amp;quot;1&amp;quot;,335559740,&amp;quot;240&amp;quot;,201341983,&amp;quot;0&amp;quot;,134233118,&amp;quot;true&amp;quot;,134233117,&amp;quot;true&amp;quot;,469778324,&amp;quot;Normal&amp;quot;]}&quot;&gt;We&#39;re&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot;&gt;&amp;nbsp;looking for a Principal Product Manager to own the vision, strategy, and execution for AI-powered recruiting at&amp;nbsp;&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot;&gt;SeekOut&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot;&gt;.&amp;nbsp;&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot;&gt;You&#39;ll&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;font-claude-response-body&quot;&gt;&amp;nbsp;define what next-generation, AI-first recruiting looks like — and lead the work to bring it to market.&lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:true,&amp;quot;134233118&amp;quot;:true,&amp;quot;201341983&amp;quot;:0,&amp;quot;335559740&amp;q